PROXY_URL="http://10.32.64.2:7264/v1/images/edits"
OUTPUT_FILE="edited_result.png"
TEST_IMAGE="test_input.jpg"

# 1. Preparing test image
if [ ! -f "$TEST_IMAGE" ]; then
    echo "📷 Creating test image file $TEST_IMAGE..."
    # Change this string on needed base64 coded image for testing
    echo "" | base64 -d > "$TEST_IMAGE"
fi

# 2. Coding image into base64
IMAGE_B64=$(base64 -w 0 "$TEST_IMAGE")

echo "🚀 Sending query for image edit..."

# 3. Curl query
RESPONSE=$(curl -s -X POST "$PROXY_URL" \
  -H "Content-Type: application/json" \
  -d "{\"image\": \"$IMAGE_B64\", \"prompt\": \"change color to cyan\"}")

# 4. Finalizing result
if echo "$RESPONSE" | jq -e '.data[0].b64_json' > /dev/null 2>&1; then
    echo "✅ Success! Saving result..."
    echo "$RESPONSE" | jq -r '.data[0].b64_json' | base64 -d > "$OUTPUT_FILE"
    echo "💾 File saved: $OUTPUT_FILE"
    ls -lh "$OUTPUT_FILE"
else
    echo "❌ Error:"
    echo "$RESPONSE" | jq .
fi
